{
  "terms": [
    {
      "term": "Voltmeter",
      "simpleDefinition": "An instrument used to measure the electrical potential difference between two points in a circuit.",
      "anchor": "Checking for 230V at a socket outlet to ensure power is present.",
      "misconception": "Thinking a voltmeter measures the flow of electricity rather than the pressure (potential) behind it."
    },
    {
      "term": "Ammeter",
      "simpleDefinition": "An instrument used to measure the rate of electrical current flow in a circuit.",
      "anchor": "Using a clamp meter around a line conductor to see how many Amps a motor is drawing.",
      "misconception": "Believing an ammeter is connected across a load like a voltmeter, which would actually cause a short circuit."
    },
    {
      "term": "Ohmmeter",
      "simpleDefinition": "An instrument used to measure electrical resistance or continuity within a component or circuit.",
      "anchor": "Testing a heating element to see if the internal wire is broken or intact.",
      "misconception": "Attempting to use an ohmmeter on a live circuit, which will damage the meter and give a false reading."
    },
    {
      "term": "Wattmeter",
      "simpleDefinition": "An instrument used to measure the instantaneous electrical power (the rate of doing work) in a circuit.",
      "anchor": "Measuring the actual power consumption of a piece of machinery while it is running.",
      "misconception": "Confusing power (Watts) with energy (kWh); a wattmeter shows the 'speed' of use, not the total amount used."
    },
    {
      "term": "Energy Meter",
      "simpleDefinition": "An instrument, often called a kilowatt-hour (kWh) meter, that measures the total electrical energy consumed over a period of time.",
      "anchor": "The main meter in a house that the electricity supplier uses to calculate the monthly bill.",
      "misconception": "Thinking an energy meter and a wattmeter are the same; one measures the 'rate' (Power) and the other measures the 'total' (Energy)."
    }
  ],
  "anchorPhrases": [
    "Voltage is measured with a Voltmeter.",
    "Current is measured with an Ammeter.",
    "Resistance is measured with an Ohmmeter.",
    "Power is measured with a Wattmeter.",
    "Energy is measured with an Energy Meter."
  ],
  "misconceptionTargets": [
    "Using generic terms like 'tester' or 'meter' instead of technically precise names like 'Ammeter' or 'Wattmeter'.",
    "Confusing the rate of power usage with the total energy consumed over time.",
    "Assuming one instrument setting can measure all quantities without manual selection."
  ]
}

